Here's a C++ function that takes a reference to a `std::string` containing Markdown formatted text and returns a `std::string` containing HTML formatted text:

```cpp
#include <string>
#include <vector>
#include <map>
#include <algorithm>
#include <iterator>

// Markdown to HTML conversion function
std::string markdownToHtml(std::string& mdText) {
    // Define mapping of Markdown to HTML syntax
    std::map<std::string, std::string> mdToHtmlMap = {
        {"#", "<h1>"}, {"##", "<h2>"}, {"###", "<h3>"},
        {"*", "<em>"}, {"**", "<strong>"},
        {"_", "<em>"}, {"__", "<strong>"},
        {"(", "<code>"}, {")", "</code>"},
        {"[", "<a href='#'>"}, {"](", "</a>"},
        {"\\n+", "<br/>"}
    };

    std::string htmlText = "";
    std::vector<std::string> tokens;

    // Split input string by whitespace characters
    std::regex pattern{R"(\s+)"};
    std::sregex_token_iterator end;
    tokens.assign(std::sregex_token_iterator(mdText.begin(), mdText.end(), pattern), end);

    // Loop through each token and apply HTML formatting
    for (const auto& token : tokens) {
        auto it = mdToHtmlMap.find(token);
        if (it!= mdToHtmlMap.end()) {
            htmlText += it->second;
            htmlText += token;
        } else {
            htmlText += token;
        }
    }

    return htmlText;
}
```

This function uses regular expressions to split the Markdown text into tokens, applies the mapping of Markdown syntax to HTML syntax, and concatenates the results to generate the final HTML-formatted string.

Example usage:

